import{_ as a,o as t,c as r,ag as l}from"./chunks/framework.CnqOxlWO.js";const g=JSON.parse('{"title":"Templates & Agent Market","description":"","frontmatter":{},"headers":[],"relativePath":"features/templates-and-market.md","filePath":"features/templates-and-market.md","lastUpdated":1773376681000}'),n={name:"features/templates-and-market.md"};function o(i,e,s,d,p,m){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="templates-agent-market" tabindex="-1">Templates &amp; Agent Market <a class="header-anchor" href="#templates-agent-market" aria-label="Permalink to &quot;Templates &amp; Agent Market&quot;">​</a></h1><p>Templates and the Agent Market are the best starting points for new users.</p><p>If you do not want to build an agent from scratch, start here.</p><h2 id="templates-vs-agent-market" tabindex="-1">Templates vs. Agent Market <a class="header-anchor" href="#templates-vs-agent-market" aria-label="Permalink to &quot;Templates vs. Agent Market&quot;">​</a></h2><p>These are two separate pages that serve different purposes.</p><h3 id="template-library" tabindex="-1">Template Library <a class="header-anchor" href="#template-library" aria-label="Permalink to &quot;Template Library&quot;">​</a></h3><p>The Template Library shows <strong>templates that are already available locally</strong>.</p><p>You will see two categories:</p><ul><li><strong>Built-in</strong> — templates that ship with the app (General, Customer Service, Coding, Writing, Translation, Data Analysis)</li><li><strong>Downloaded</strong> — templates you have downloaded from the Agent Market</li></ul><h3 id="agent-market" tabindex="-1">Agent Market <a class="header-anchor" href="#agent-market" aria-label="Permalink to &quot;Agent Market&quot;">​</a></h3><p>The Agent Market is a <strong>discovery page for browsing and downloading templates</strong> created by the community.</p><p>Downloaded templates do not become agents automatically. They first go into your Template Library, and you then decide whether to create an agent from them.</p><h2 id="using-the-template-library" tabindex="-1">Using the Template Library <a class="header-anchor" href="#using-the-template-library" aria-label="Permalink to &quot;Using the Template Library&quot;">​</a></h2><p>From the Template Library page, you can:</p><ul><li>Search templates by name</li><li>View a template&#39;s README</li><li>Create an agent from a template</li></ul><h3 id="creating-an-agent-from-a-template" tabindex="-1">Creating an Agent from a Template <a class="header-anchor" href="#creating-an-agent-from-a-template" aria-label="Permalink to &quot;Creating an Agent from a Template&quot;">​</a></h3><ol><li>Select a template.</li><li>Click <strong>Create Agent</strong>.</li><li>Enter a name for the agent.</li><li>Confirm.</li></ol><p>The agent is created and appears in the sidebar. A platform model source is usually pre-selected automatically.</p><p>If you want to skip model selection during creation, you can assign one later in <a href="/clawdsaber-docs/features/agent-config.html">Agent Configuration</a>.</p><h3 id="readme" tabindex="-1">README <a class="header-anchor" href="#readme" aria-label="Permalink to &quot;README&quot;">​</a></h3><p>Many templates include a README that explains:</p><ul><li>What the template is designed for</li><li>Its default behavior</li><li>Whether additional skills or channels are required</li></ul><p>It is worth reading the README before creating an agent.</p><h3 id="deleting-downloaded-templates" tabindex="-1">Deleting Downloaded Templates <a class="header-anchor" href="#deleting-downloaded-templates" aria-label="Permalink to &quot;Deleting Downloaded Templates&quot;">​</a></h3><p>You can delete downloaded templates from the library. Deleting a template does <strong>not</strong> delete any agents that were already created from it.</p><h2 id="using-the-agent-market" tabindex="-1">Using the Agent Market <a class="header-anchor" href="#using-the-agent-market" aria-label="Permalink to &quot;Using the Agent Market&quot;">​</a></h2><p>From the Agent Market page, you can:</p><ul><li>Search for templates</li><li>View version, author, download count, and tags</li><li>Download templates to your local library</li></ul><p>Template cards display localized names and descriptions based on your current app language.</p><h3 id="after-downloading" tabindex="-1">After Downloading <a class="header-anchor" href="#after-downloading" aria-label="Permalink to &quot;After Downloading&quot;">​</a></h3><ol><li>Click <strong>Download</strong> on a template card.</li><li>The status changes to &quot;Downloaded&quot;.</li><li>The template appears in the Template Library under the <strong>Downloaded</strong> section.</li><li>Go to the Template Library to create an agent from it.</li></ol><h2 id="recommendation-for-new-users" tabindex="-1">Recommendation for New Users <a class="header-anchor" href="#recommendation-for-new-users" aria-label="Permalink to &quot;Recommendation for New Users&quot;">​</a></h2><p>If you just want to experience the full workflow:</p><ol><li>Open the Template Library.</li><li>Pick a built-in template.</li><li>Create your first agent.</li><li>Once that is working, explore the Agent Market for community templates.</li></ol><p>This approach is more reliable and avoids getting overwhelmed by choices early on.</p>',35)])])}const c=a(n,[["render",o]]);export{g as __pageData,c as default};
